from typing import Annotated, Sequence
from langgraph.graph import StateGraph, END
from typing_extensions import TypedDict

class AgentState(TypedDict):
    messages: Annotated[Sequence[str], 'add']
    planned_queries: list[str]
    retrieved_chunks: list[dict]  # {'content': str, 'source': str, 'score': float}
    citations: list[dict]  # {'chunk_id': int, 'source': str}
    confidence: float

    def update_citations(self, new_cites: list[dict]) -> 'AgentState':
        self['citations'].extend(new_cites)
        return self

from langchain_openai import ChatOpenAI

llm = ChatOpenAI(model='gpt-4o', temperature=0)

def planner_node(state: AgentState) -> AgentState:
    prompt = f"""Decompose into 2-3 specific retrieval queries:
Current question: {state['messages'][-1]}
Output ONLY JSON array of queries."""

    response = llm.invoke(prompt)
    queries = response.content.strip('[]').split(',')

    return {
        'planned_queries': [q.strip('"') for q in queries],
        'messages': state['messages'] + [f'Planned: {queries}']
    }

