def synthesizer_node(state: AgentState) -> AgentState:
    chunks_text = '\n'.join([c['content'] for c in state['retrieved_chunks']])
    sources = list(set(c['source'] for c in state['retrieved_chunks']))

    prompt = f"""Synthesize answer using ONLY these chunks:
{schunks_text}

Sources: {sources}

Answer question: {state['messages'][0]}
Format: Answer:\n\nSources: [1], [2] etc"""

    response = llm.invoke(prompt)
    citations = [{'chunk_id': i, 'source': c['source']} 
                for i, c in enumerate(state['retrieved_chunks'])]

    return {
        'messages': state['messages'] + [response.content],
        'citations': citations,
        'confidence': sum(c['score'] for c in state['retrieved_chunks'])/len(state['retrieved_chunks'])
    }

