def vex_source_verifier(state: AgentState) -> AgentState:
    if not state['retrieved_chunks']:
        raise ValueError('No chunks retrieved')

    # Vex verifies answer uses only provided chunks
    verification = vex_client.verify(
        claim=state['messages'][-1],
        evidence=[c['content'] for c in state['retrieved_chunks']],
        checks=['source-faithfulness', 'no-hallucination'],
        context={'sources': [c['source'] for c in state['retrieved_chunks']]}
    )

    if not verification.passed:
        state['messages'].append('VERIFICATION FAILED: Regenerating...')
        return {'needs_regeneration': True}

    return {'faithfulness_score': verification.score}
